<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';exigirRol(['usuario']);require_once dirname(__DIR__,2).'/includes/carrito.php';$pdo=obtenerConexion();$dirs=direccionesUsuario($pdo,(int)$_SESSION['usuario_id']);$deps=$pdo->query('SELECT id,nombre FROM departamentos ORDER BY nombre')->fetchAll();$portal=portalEstudianteCabecera('Mis direcciones','direcciones','Administra direcciones de entrega vinculadas únicamente a tu cuenta.');?>
<div class="row g-4"><div class="col-lg-7"><div class="card"><div class="card-body"><h2 class="h5">Direcciones guardadas</h2><?php foreach($dirs as$d):?><div class="border rounded p-3 mb-3"><div class="d-flex justify-content-between"><strong><?=atenea_e(etiquetaDireccion($d))?> <?=$d['predeterminada']?'<span class="badge bg-success">Predeterminada</span>':''?></strong><div class="d-flex gap-2"><a class="btn btn-sm btn-outline-primary" href="<?=atenea_url('src/estudiantes/direccion-editar.php?id='.$d['id'])?>">Editar</a><form method="post" action="<?=atenea_url('src/direcciones/eliminar.php')?>"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$d['id']?>"><button class="btn btn-sm btn-outline-danger">Desactivar</button></form></div></div><div><?=atenea_e($d['receptor'])?> · <?=atenea_e($d['telefono'])?></div><small class="text-muted"><?=atenea_e($d['direccion_detallada'].', '.$d['municipio'].', '.$d['departamento'])?></small></div><?php endforeach;?><?php if(!$dirs):?><p class="text-muted py-4 text-center">Todavía no tienes direcciones guardadas.</p><?php endif;?></div></div></div>
<div class="col-lg-5"><div class="card"><div class="card-body"><h2 class="h5">Nueva dirección</h2><form method="post" action="<?=atenea_url('src/direcciones/guardar.php')?>" class="row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><div class="col-6"><label class="form-label">Etiqueta</label><select class="form-select" name="etiqueta" required><option value="casa">Casa</option><option value="oficina">Oficina</option><option value="otra">Otra</option></select></div><div class="col-6"><label class="form-label">Etiqueta personalizada</label><input class="form-control" name="etiqueta_personalizada" maxlength="60"></div><div class="col-12"><label class="form-label">Receptor</label><input class="form-control" name="receptor" maxlength="160" required></div><div class="col-12"><label class="form-label">Teléfono</label><input class="form-control" name="telefono" maxlength="30" required></div><div class="col-12"><label class="form-label">Departamento</label><select class="form-select" id="direccionDepartamento" name="departamento_id" required><option value="">Selecciona</option><?php foreach($deps as$d):?><option value="<?=$d['id']?>"><?=atenea_e($d['nombre'])?></option><?php endforeach;?></select></div><div class="col-6"><label class="form-label">Municipio</label><select class="form-select" id="direccionMunicipio" name="municipio_id" required disabled><option value="">Selecciona</option></select></div><div class="col-6"><label class="form-label">Distrito</label><select class="form-select" id="direccionDistrito" name="distrito_id" disabled><option value="">No aplica</option></select></div><div class="col-12"><label class="form-label">Dirección detallada</label><textarea class="form-control" name="direccion_detallada" maxlength="500" required></textarea></div><div class="col-12"><label class="form-label">Referencias</label><textarea class="form-control" name="referencias" maxlength="500"></textarea></div><div class="col-12 form-check ms-2"><input class="form-check-input" type="checkbox" name="predeterminada" value="1" id="pred"><label class="form-check-label" for="pred">Predeterminada</label></div><div class="col-12"><button class="btn btn-primary">Guardar dirección</button></div></form></div></div></div></div><script>(function(){const d=document.getElementById('direccionDepartamento'),m=document.getElementById('direccionMunicipio'),i=document.getElementById('direccionDistrito');async function fill(el,t,p){el.innerHTML='<option value="">Selecciona</option>';el.disabled=!p;if(!p)return;const r=await fetch('<?=atenea_url('src/api/ubicaciones.php')?>?tipo='+t+'&padre='+encodeURIComponent(p),{credentials:'same-origin'});for(const v of await r.json()){const o=document.createElement('option');o.value=v.id;o.textContent=v.nombre;el.appendChild(o);}}d.addEventListener('change',async()=>{await fill(m,'municipios',d.value);await fill(i,'distritos','');});m.addEventListener('change',()=>fill(i,'distritos',m.value));})();</script><?php portalEstudiantePie();
